Index: infra/app-vm.ts
===================================================================
--- infra/app-vm.ts	
+++ infra/app-vm.ts	
@@ -0,0 +1,191 @@
+import * as oci from "@pulumi/oci";
+import * as pulumi from "@pulumi/pulumi";
+
+export interface AppVmArgs {
+  compartmentId: string;
+  subnetId: pulumi.Input<string>;
+  sshPublicKey: string;
+  dbPrivateIp: string;
+  dbPassword: pulumi.Output<string>;
+  dbUser: string;
+  dbName: string;
+  betterAuthSecret: pulumi.Output<string>;
+  betterAuthUrl: string;
+  r2AccessKeyId: pulumi.Output<string>;
+  r2SecretAccessKey: pulumi.Output<string>;
+  r2AccountId: string;
+  r2BucketName: string;
+  r2PublicUrl: string;
+  publicPosthogKey: pulumi.Output<string>;
+  publicPosthogHost: string;
+  appDomain: string;
+  repoUrl: string;
+  repoBranch: string;
+}
+
+export interface AppVmResult {
+  publicIp: pulumi.Output<string>;
+  privateIp: string;
+}
+
+const APP_PRIVATE_IP = "10.0.1.10";
+
+export function createAppVm(args: AppVmArgs): AppVmResult {
+  const ads = oci.Identity.getAvailabilityDomainsOutput({
+    compartmentId: args.compartmentId,
+  });
+
+  const images = oci.Core.getImagesOutput({
+    compartmentId: args.compartmentId,
+    operatingSystem: "Canonical Ubuntu",
+    operatingSystemVersion: "22.04",
+    shape: "VM.Standard.A1.Flex",
+  });
+
+  const userData = pulumi
+    .all([
+      args.dbPassword,
+      args.betterAuthSecret,
+      args.r2AccessKeyId,
+      args.r2SecretAccessKey,
+      args.publicPosthogKey,
+    ])
+    .apply(([dbPw, authSecret, r2Key, r2Secret, posthogKey]) => {
+      const caddyBlock = args.appDomain
+        ? `${args.appDomain} {\n  reverse_proxy localhost:3020\n}`
+        : `:80 {\n  reverse_proxy localhost:3020\n}`;
+
+      const envLines = [
+        `DATABASE_URL=REDACTED`,
+        `BETTER_AUTH_SECRET=${authSecret}`,
+        `BETTER_AUTH_URL=${args.betterAuthUrl}`,
+        `R2_ACCESS_KEY_ID=${r2Key}`,
+        `R2_SECRET_ACCESS_KEY=${r2Secret}`,
+        `R2_ACCOUNT_ID=${args.r2AccountId}`,
+        `R2_BUCKET_NAME=${args.r2BucketName}`,
+        `R2_PUBLIC_URL=${args.r2PublicUrl}`,
+      ];
+
+      if (posthogKey) {
+        envLines.push(`PUBLIC_POSTHOG_KEY=${posthogKey}`);
+      }
+      if (args.publicPosthogHost) {
+        envLines.push(`PUBLIC_POSTHOG_HOST=${args.publicPosthogHost}`);
+      }
+
+      const cloneBlock = args.repoUrl
+        ? `git clone --branch ${args.repoBranch} ${args.repoUrl} /opt/alpauls-ats/app`
+        : "echo 'No repoUrl configured — deploy app manually to /opt/alpauls-ats/app'";
+
+      const buildBlock = args.repoUrl
+        ? `su - alpauls -c "cd /opt/alpauls-ats/app && /home/alpauls/.bun/bin/bun install && /home/alpauls/.bun/bin/bun run build"`
+        : "echo 'Skipping build — no repoUrl configured'";
+
+      const cloudInit = `#cloud-config
+package_update: true
+package_upgrade: true
+
+packages:
+  - git
+  - curl
+  - ufw
+
+users:
+  - name: alpauls
+    system: false
+    shell: /bin/bash
+    sudo: ALL=(ALL) NOPASSWD:ALL
+
+write_files:
+  - path: /etc/caddy/Caddyfile
+    content: |
+      ${caddyBlock}
+    owner: caddy:caddy
+    permissions: "0644"
+  - path: /opt/alpauls-ats/.env.local
+    content: |
+      ${envLines.join("\n")}
+    owner: alpauls:alpauls
+    permissions: "0600"
+  - path: /etc/systemd/system/alpauls-ats.service
+    content: |
+      [Unit]
+      Description=Alpauls ATS
+      After=network.target
+
+      [Service]
+      Type=simple
+      User=alpauls
+      WorkingDirectory=/opt/alpauls-ats/app
+      ExecStart=/home/alpauls/.bun/bin/bun run .output/server/index.mjs
+      Restart=always
+      RestartSec=5
+      EnvironmentFile=/opt/alpauls-ats/.env.local
+
+      [Install]
+      WantedBy=multi-user.target
+
+runcmd:
+  - install -d -o alpauls -g alpauls /opt/alpauls-ats/app
+  - ${cloneBlock}
+  - su - alpauls -c "curl -fsSL https://bun.sh/install | bash"
+  - ${buildBlock}
+  - install -m 0755 -d /usr/share/keyrings
+  - curl -1sLf https://dl.cloudsmith.io/public/caddy/stable/gpg.key | gpg --dearmor -o /usr/share/keyrings/caddy-stable-archive-keyring.gpg
+  - curl -1sLf https://dl.cloudsmith.io/public/caddy/stable/debian.deb.txt | tee /etc/apt/sources.list.d/caddy-stable.list
+  - apt-get update
+  - apt-get install -y caddy
+  - ufw allow 22/tcp
+  - ufw allow 80/tcp
+  - ufw allow 443/tcp
+  - ufw --force enable
+  - systemctl enable caddy
+  - systemctl start caddy
+  - systemctl enable alpauls-ats
+  - systemctl start alpauls-ats
+`;
+      return Buffer.from(cloudInit).toString("base64");
+    });
+
+  const instance = new oci.Core.Instance("app-vm", {
+    availabilityDomain: ads.availabilityDomains[0].name,
+    compartmentId: args.compartmentId,
+    createVnicDetails: {
+      assignPublicIp: true,
+      hostnameLabel: "app",
+      privateIp: APP_PRIVATE_IP,
+      subnetId: args.subnetId,
+    },
+    displayName: "alpauls-ats-app",
+    metadata: {
+      ssh_authorized_keys: args.sshPublicKey,
+      user_data: userData,
+    },
+    shape: "VM.Standard.A1.Flex",
+    shapeConfig: {
+      memoryInGbs: 2,
+      ocpus: 1,
+    },
+    sourceDetails: {
+      bootVolumeSizeInGBs: 50,
+      imageId: images.id,
+      sourceType: "image",
+    },
+  });
+
+  const vnicAttachments = oci.Core.getVnicAttachmentsOutput({
+    compartmentId: args.compartmentId,
+    instanceId: instance.id,
+  });
+
+  const vnicId = vnicAttachments.apply(
+    (r) => r.vnicAttachments[0]?.vnicId ?? "",
+  );
+
+  const vnic = oci.Core.getVnicOutput({ vnicId });
+
+  return {
+    privateIp: APP_PRIVATE_IP,
+    publicIp: vnic.publicIp,
+  };
+}

